CREATE TRIGGER [dbo].[Part_History]ON [dbo].[Part]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.PartId IS NOT NULL AND d.PartId IS NULL THEN 'I' 		WHEN i.PartId IS NOT NULL AND d.PartId IS NOT NULL THEN 'U' 		WHEN i.PartId IS NULL AND d.PartId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.PartId = d.PartId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.dbo_Part([PartId], [PartTypeId], [PartNumber], [PartRevision], [Description], [UnitOfMeasureId], [IsActive], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [PartId], [PartTypeId], [PartNumber], [PartRevision], [Description], [UnitOfMeasureId], [IsActive], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.dbo_Part([PartId], [PartTypeId], [PartNumber], [PartRevision], [Description], [UnitOfMeasureId], [IsActive], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [PartId], [PartTypeId], [PartNumber], [PartRevision], [Description], [UnitOfMeasureId], [IsActive], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND